   180	pub fn parse_scope_git_remote(api_url: &str, remote_url: &str) -> anyhow::Result<(String, String)> {
   181	    let api = Url::parse(api_url).context("parse Scope API URL")?;
   182	    let remote = Url::parse(remote_url).context("parse Scope Git remote URL")?;
   183	
   184	    if api.scheme() != remote.scheme()
   185	        || api.host_str() != remote.host_str()
   186	        || api.port_or_known_default() != remote.port_or_known_default()
   187	    {
   188	        bail!(
   189	            "Scope remote points at {}, but this CLI is configured for {}",
   190	            redacted_url(&remote),
   191	            api.as_str().trim_end_matches('/')
   192	        );
   193	    }
   194	
   195	    if remote.password().is_some() {
   196	        bail!("Scope Git remote URL cannot include a password");
   197	    }
   198	
   199	    let segments = remote
   200	        .path_segments()
   201	        .map(|segments| segments.collect::<Vec<_>>())
   202	        .unwrap_or_default();
   203	    if segments.len() != 4 || segments[0] != "git" || segments[1] != "permissioned" {
   204	        bail!("Scope remote must have path /git/permissioned/owner/repo");
   205	    }
   206	
   207	    let owner = segments[2].trim();
   208	    let repo = segments[3].trim();
   209	    if owner.is_empty() || repo.is_empty() {
   210	        bail!("Scope remote must have path /git/permissioned/owner/repo");
   211	    }
   212	
   213	    Ok((owner.to_string(), repo.to_string()))
   214	}
