   216	fn redacted_url(url: &Url) -> String {
   217	    let mut redacted = url.clone();
   218	    if !redacted.username().is_empty() {
   219	        let _ = redacted.set_username("redacted");
   220	    }
   221	    if redacted.password().is_some() {
   222	        let _ = redacted.set_password(Some("redacted"));
   223	    }
   224	    redacted.to_string()
   225	}
